; 愚者の倉庫

name = 愚者の倉庫５
insideName = Floor 5
level = 23
bgm = trick
shadow = dark
sky = black
roof = stone
blank = rock
antiWarp = true

; 各パーツ
━ = stone
　 = marble
☆ = soilr
❑ = cube
⧻ = fence
☖ = arch
☗ = gate
︻ = panel

; 移動ポイント
(A) = map:愚者の倉庫４, x:4, y:0, way:n, symbol:exit, ask:Go to the previous floor?
(B) = map:愚者の倉庫６, x:0, y:10, way:e, symbol:exit, ask:Go to the next floor?

; 宝箱
box[1] = 罠はない,グレートソード,修理の巻物,アウラの宝珠,アウラの宝珠

